import Highcharts from 'highcharts';
import HighchartsReact from 'highcharts-react-official';
import React, { Component } from 'react';

export default class Copmparison extends Component {

    constructor(props) {
        super(props);
        this.state = {

            title: {
                text: 'COVID-19 Cases'
            },

            subtitle: {
                text: 'Source: covid19api.com'
            },

            yAxis: {
                title: {
                    text: 'Number of Cases'
                }
            },

            xAxis: {
                type: 'datetime',
            },

            legend: {
                layout: 'vertical',
                align: 'right',
                verticalAlign: 'middle'
            },

            plotOptions: {
                series: {
                    label: {
                        connectorAllowed: false
                    },
                }
            },

            responsive: {
                rules: [{
                    condition: {
                        maxWidth: 500
                    },
                    chartOptions: {
                        legend: {
                            layout: 'horizontal',
                            align: 'center',
                            verticalAlign: 'bottom'
                        }
                    }
                }]
            },

            series: [],

        };
    }

    render() {
        return <HighchartsReact highcharts={Highcharts} options={this.state} />;
    }

    async componentDidMount() {
        const { country } = this.props;
        const countryStats = await (await fetch(`https://api.covid19api.com/total/country/${country}/status/confirmed`)).json();
        debugger;
        this.setState({
            series: [{
                name: countryStats[0]['Country'],
                data: countryStats.map(({ Date: date, Cases: cases }) => ({ x: Date.parse(date), y: cases })),
            }],
        });
    }

}